var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그거 사람들에게 나눠 줘.","JPN":"それはみんなに配ってくれ。","ENG":"Hand those out to people.","TWN":"把那個分給大家吃吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"포춘 쿠키를? 공짜로?","JPN":"フォーチュンクッキーを？　タダで？","ENG":"The fortune cookies? For free?","TWN":"幸運餅乾嗎？免費送？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"어찌 됐건 하트 포인트 덕분에 물리친 거잖아. 사은품이라고 해 두지 뭐.","JPN":"とにかくハートポイントのおかげで倒せたんだ。プレゼントということにしておこう。","ENG":"Well, we defeated them thanks to the Heart Points. Let's just say it's a souvenir.","TWN":"因為那些愛心點數才能趕走她的嘛，就當是謝禮吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아주 좋은 생각이야.","JPN":"それはいい考えね。","ENG":"That's a great idea.","TWN":"好主意。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"너어! 지금 두 번째 받는 거 다 기억해!","JPN":"君！　これで二度目でしょ！　ちゃんと覚えてるんだからね！","ENG":"Hey! I know this is your second time getting a cookie!","TWN":"你！是第二次來領吧！我都有記住喔！"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"하나씩 받는 거야! 또 받으러 오면 가만 안 둔다?","JPN":"一つずつだよ！　また貰いに来たら承知しないよ？","ENG":"It's one per person, okay! Don't come back for more!","TWN":"每人只能領一塊！再來領我就要生氣囉！"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"운세 중에 액운이 나온 분들은 말씀해 주세요!","JPN":"運勢で凶が出た人は言ってくださいね！","ENG":"Let us know if you got misfortune as your result!","TWN":"運勢出現凶的人請找我！"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"액운이랑 작은 선물이랑 바꿔 드립니다~","JPN":"凶を小さなプレゼントに交換してあげますよ～","ENG":"You can exchange it for a small gift!","TWN":"我們會用小禮物換走厄運～"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"점장님이시죠? 기획하시느라 고생 깨나 하셨겠는데요?","JPN":"店長さんですか？　企画でご苦労なさったでしょう？","ENG":"You're the owner, right? You must've gone through a lot of trouble to make this happen.","TWN":"你就是店長吧？策劃這場活動應該花不少力氣吧？"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L15_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"덕분에 좋은 기사가 나올 것 같아요. 좋은 공연, 감사합니다.","JPN":"おかげでいい記事が書けそうです。いいイベントをありがとうございました。","ENG":"It'll make a good article, though. Thank you for the great performance.","TWN":"多虧你們，我應該能寫一篇不錯的報導，謝謝你們的精彩演出。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"잘 봐 줬다니 고맙네.","JPN":"楽しんでくれたようで、よかった。","ENG":"I'm glad you enjoyed it.","TWN":"也謝謝你來看我們的表演。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"여기 특별한 마법을 걸어 만든 웨딩 디저트야. <color=#ffd34c>행복한 신부가 될 수 있는 마법</color>이 걸려 있어.","JPN":"これは特別な魔法をかけて作ったウェディングデザートだ。<color=#ffd34c>幸せな花嫁になれる魔法</color>がかけてある。","ENG":"Here. It's a wedding dessert with a special spell cast on it. The spell will help you become a <color=#ffd34c>happy bride</color>.","TWN":"這是施加特別魔法的婚禮甜點，就是<color=#ffd34c>成為幸福新娘的魔法</color>。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"와. 아껴 뒀다 먹어야겠네요. 아직은 상대가 없어서요.","JPN":"わあ。大切に保管して食べないといけませんね。まだ相手がいなくて。","ENG":"Ooh. I should save it for the future, then. I don't have anyone special yet.","TWN":"哇，我現在又沒有對象，那要先收起來，等之後才能吃。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"흐음…… 아닌가?","JPN":"ふむ……いや、いるのかな？","ENG":"Hmm... Or maybe I do.","TWN":"嗯……或許有吧？"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"뭐, 그건 알아서 하고.","JPN":"まあ、それは勝手にやってくれ。","ENG":"Well, you do you.","TWN":"喔喔，隨便你要什麼時候吃。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"꼬마. 너도 포춘 쿠키 하나 받아 가.","JPN":"ちびっ子。汝もフォーチュンクッキーを貰っていくといい。","ENG":"Hey kid, take a fortune cookie.","TWN":"小朋友，也送你一塊幸運餅乾。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"감사합니다, 공주… 아니, 마녀 신부님!","JPN":"ありがとう、お姫……じゃなかった、魔女の花嫁さん！","ENG":"Thank you, princ– I mean, witch bride!","TWN":"謝謝公主……不對，是魔女新娘！"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"오늘 멋있었어요! 꺄악!","JPN":"今日カッコよかったよ！　きゃっ！","ENG":"You were so cool today! Ahhh!","TWN":"你今天好酷喔！哎唷！"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"…멋있다면서 도망은 왜 치는 거야?","JPN":"……カッコよかったって言いながら、なんで逃げるんだ？","ENG":"...Why is she complimenting me and running away?","TWN":"……說我很酷後幹嘛跑掉？"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"부끄러워서 그렇지. 귀여운 꼬마 손님이었네.","JPN":"きっと恥ずかしいのよ。かわいらしいお客さんだったわね。","ENG":"She's just shy. What an adorable little guest.","TWN":"應該是害羞吧，真是位可愛的客人。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"…한 세 개 챙겨줄 걸 그랬나. 크흠.","JPN":"……三つくらいあげたらよかったかな。コホン。","ENG":"...Maybe I should've given her more cookies. Ahem.","TWN":"……剛應該送她三塊的，咳咳。"},"stage":{"bg":"WEDDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"와~ 북적북적하네.","JPN":"わ～、人でいっぱいね。","ENG":"Wow! It's so busy here.","TWN":"哇～還真是熱鬧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그래서 네가 계획했던 그 피로연은 어떻게 할 거야?","JPN":"それで、汝が計画した披露宴とやらはどうするんだ？","ENG":"So, what are you gonna do with the wedding reception you planned?","TWN":"那你原本策劃的那個婚宴要怎麼辦？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그걸 꼭 진행해야 되나? 지금도 충분히 축제 같은걸?","JPN":"別にやらなくてもいいんじゃないかしら？　今でも十分お祭りみたいよ？","ENG":"Do we have to go through with that? It's festive enough as it is.","TWN":"那個還有需要嗎？現在活動的氛圍應該很夠吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"원하던 대답이야. 여기서 뭘 더 하라고 했으면 이벤트고 뭐고 다 날려 버렸을 지도 몰라.","JPN":"期待どおりの答えだな。ここでさらに何かしようと言ったら、イベントも何もかも吹っ飛ばしていたところだ。","ENG":"Good. I would've blown everything up if you were going to try anything else.","TWN":"這就是我想要的答案，要是再叫我做什麼，就算是活動還什麼的我才不管！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저기.","JPN":"あの。","ENG":"Excuse me.","TWN":"喂。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"여기 포춘 쿠키요.","JPN":"……どうぞ、フォーチュンクッキーです。","ENG":"Here. It's a fortune cookie.","TWN":"送你幸運餅乾。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"내게도 이걸 주는 건가요?","JPN":"私にもこれを？","ENG":"Why are you giving me this?","TWN":"我也有嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네에, 뭐… 생긴 건 마음에 안 들지만, 아무튼 우릴 도와줬으니까요.","JPN":"ええ……外見はあれですけど、私たちを助けてくれましたから。","ENG":"Uh, well... I don't like how you look, but, you helped us.","TWN":"嗯……雖然我不喜歡你，但是你幫我們趕走她的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"그래…….","JPN":"そう……","ENG":"I see...","TWN":"是嗎……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"이건 둘만의 축제가 아니라, 모두의 축제라는 건가.","JPN":"これは二人だけのお祭りではなくて、みんなのお祭りということなのかしら。","ENG":"This is an event for everyone, not just two people.","TWN":"這不只是二個人的喜宴，而是所有人的嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"훗.","JPN":"ふっ。","ENG":"Hah.","TWN":"呵。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"고통 대신 기쁨의 눈물이라. 때론 이것도 나쁘지 않겠군요.","JPN":"苦痛の代わりに喜びの涙とはね。こういうのも時には悪くないでしょう。","ENG":"Tears of joy, instead of tears of agony. I guess that's occasionally acceptable.","TWN":"喜悅的淚水代替痛苦的淚水，有時候這樣也還不錯。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"물론… 당신을 무릎 꿇릴 일은 여전히 기대하고 있답니다. 여. 보.","JPN":"もちろん……跪かせることも期待しています。あ・な・た。","ENG":"Of course... I still look forward to having you kneel under me, Sweet Heart.","TWN":"不過……我仍然很期待讓你跪在我腳下，老公。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};